def solve(vals):
    from collections import deque
    if not vals: return True
    # Build tree
    nodes = [None if v == -1 else int(v) for v in vals]
    if not nodes: return True

    def validate(idx, lo, hi):
        if idx >= len(nodes) or nodes[idx] is None: return True
        v = nodes[idx]
        if v <= lo or v >= hi: return False
        return validate(2*idx+1, lo, v) and validate(2*idx+2, v, hi)

    return validate(0, float('-inf'), float('inf'))

